func TestChatCompletion_ResponseMapping(t *testing.T) {
	tests := []struct {
		name           string
		finishReason   string
		expectedStatus string
	}{
		{
			name:           "stop finish reason maps to complete",
			finishReason:   "stop",
			expectedStatus: "complete",
		},
		{
			name:           "tool_calls finish reason maps to tool_call",
			finishReason:   "tool_calls",
			expectedStatus: "tool_call",
		},
		{
			name:           "length finish reason maps to complete",
			finishReason:   "length",
			expectedStatus: "complete",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
				response := map[string]any{
					"id":      "chatcmpl-test",
					"object":  "chat.completion",
					"created": 1677652288,
					"model":   "gpt-4",
					"choices": []map[string]any{
						{
							"index": 0,
							"message": map[string]any{
								"role":    "assistant",
								"content": "Response",
							},
							"finish_reason": tt.finishReason,
						},
					},
					"usage": map[string]any{
						"prompt_tokens":     5,
						"completion_tokens": 5,
						"total_tokens":      10,
					},
				}

				// Add tool_calls if finish_reason is tool_calls
				if tt.finishReason == "tool_calls" {
					choices := response["choices"].([]map[string]any)
					choices[0]["message"].(map[string]any)["tool_calls"] = []map[string]any{
						{
							"id":   "call_test",
							"type": "function",
							"function": map[string]any{
								"name":      "test_func",
								"arguments": "{}",
							},
						},
					}
				}

				w.Header().Set("Content-Type", "application/json")
				json.NewEncoder(w).Encode(response)
			}))
			defer server.Close()

			endpoint := &model.EndpointConfig{
				URL:       server.URL,
				Model:     "gpt-4",
				MaxTokens: 128000,
			}

			client, err := agenticmodel.NewClient(endpoint)
			if err != nil {
				t.Fatalf("NewClient() failed: %v", err)
			}

			req := agentic.AgentRequest{
				RequestID: "req-test",
				Messages: []agentic.ChatMessage{
					{Role: "user", Content: "Test"},
				},
				Model: "gpt-4",
			}

			ctx := context.Background()
			resp, err := client.ChatCompletion(ctx, req)
			if err != nil {
				t.Fatalf("ChatCompletion() failed: %v", err)
			}

			if resp.Status != tt.expectedStatus {
				t.Errorf("Status = %s, want %s", resp.Status, tt.expectedStatus)
			}
		})
	}
}

